VALUES
  ('social-worker-moex-00021', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關心理防衛機轉，下列那一個解釋不適當？', '["合理化是指以自認為符合邏輯的理由來說明或解釋自己的行為", "替代是指把對某個人事物的負向情緒轉移或發洩到另一個比較對自己沒有威脅的人事物上", "遇到挫折挑戰時以較原始、本能衝動的反應來處理叫做退化", "抽離是指以另一種行為來彌補之前行為所引發的焦慮或負向感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00022', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'MaryAinsworth及其同僚（1978）建構一個陌生情境蒐集母嬰之互動，實驗之後，嬰兒的反應分 為三種模式，下列那一個描述不正確？', '["安全型依附（secureattachment）的嬰兒，當母親與陌生人在身旁時，會認為母親同在，也會與 陌生人互動", "迴避型依附（avoidantattachment）的嬰兒不在乎母親是否同在或是離開，對於母親離開無動於衷", "典型的黏人寶寶，即使母親與陌生人同時在場，也不會和陌生人互動，此類屬於迴避型依附 （avoidantattachment）的嬰兒", "母親離開時，嬰兒會很生氣，哭泣許久，不易安撫，是屬於焦慮型依附（anxiousattachment）的 嬰兒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00023', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '到了成年中期可能會出現慢性疾病或是有癌症風險，所謂的三高問題與慢性疾病有很大的關聯， 下列那個不是所謂的三高問題？', '["高血脂", "高血壓", "高尿酸", "高血糖"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00024', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '平權法案或稱肯定性行動（affirmativeaction）是反歧視的重要作法。下列與它相關的敘述，何者 錯誤？', '["它源自於美國1960年代，要求雇主與機構定額僱用女性及少數族裔的民權法案", "持自由的個人主義觀點者（liberalindividualist）認為平權法案會帶來反向歧視，讓事情變更糟", "針對平權法案反對者的說法，可以使用挫折－攻擊論來解釋", "羅爾斯（Rawls）分配性正義（distributivejustice）觀點支持者，反對平權法案是制度性歧視的 因應策略"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00025', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童問題可以分成內化或外顯問題兩種，下列何者屬於外顯問題？', '["焦慮", "憂鬱", "過動", "退縮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00026', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '主張透過檢視少數群體家庭所身處的撫育系統（nurturingsystem）和維持系統（sustainingsystem） 來提高社會工作者思考文化多樣性，屬於下列那一種觀點？', '["發展視角（developmentalperspective）", "復原力視角（resilienceperspective）", "雙元視角（dualperspective）", "脆強性視角（fragileperspective）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00027', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那個理論強調社會中因老化所產生的問題，多來自於老年人周遭環境與其自我概念之間的負 面互動？', '["撤退理論", "社會再建構理論", "角色理論", "社會繼續理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00028', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '癌症已占據國人十大死因的前三名多年，因此癌症治療後的性生活復原處遇，也日形重要。有關 此議題之處遇原則，下列何者正確？', '["為促進個案復原的過程，最好在治療後儘快開始勃起障礙的治療和性生活的復原", "為促進個案復原的過程，應避免在治療後太快開始勃起障礙的治療和性生活的復原", "為避免不自然的性生活復原，應避免使用勃起藥物或植入真空勃起裝置", "為避免伴侶尷尬、焦慮或恐懼，應單獨對個案提供性復原處遇，而不將伴侶納入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00029', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關發展遲滯（failuretothrive）的敘述，下列何者錯誤？', '["非器質性的發展遲滯可能跟照顧者欠缺以情感回應、滿足其需求的能力有關", "飲食混亂不穩定、營養不良也可能導致嬰幼兒發展遲緩", "發展遲滯只要協助家長培養餵食問題的技巧，即可改善", "早產是另一個可能造成發展遲滯的因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00030', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於青少年的社交技巧訓練，下列敘述何者最不適當？', '["目的在找出青少年對問題情境的「病理性回應」然後加以去除", "重點為協助青少年學習新的行為，讓新的行為帶來正向結果", "處遇焦點可能包含協助青少年面對同儕壓力", "透過設計腳本和實施角色演練，讓青少年熟悉問題解決方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
